import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        # Validate filename is not empty
        if not filename or not filename.strip():
            return ''

        # Check for path traversal attempts
        if '..' in filename or filename.startswith('/') or filename.startswith('\\'):
            return ''

        # Join the directory path and filename
        file_path = os.path.join(dir_path, filename)

        # Resolve to absolute paths
        abs_file_path = os.path.realpath(file_path)
        abs_dir_path = os.path.realpath(dir_path)

        # Verify the file is within the intended directory
        if not abs_file_path.startswith(abs_dir_path + os.sep):
            return ''

        # Read the file content
        with open(file_path, 'r') as f:
            return f.read()
    except Exception:
        return ''

