def get_ls_result(dir_path: str) -> str:
    try:
        # Validate that the path exists and is a directory
        if not os.path.isdir(dir_path):
            return ""

        # Use subprocess with list of arguments to avoid shell injection
        result = subprocess.run(
            ['ls', '-l', dir_path],
            capture_output=True,
            text=True,
            timeout=10
        )

        # Return stdout only if the command succeeded
        if result.returncode == 0:
            return result.stdout
        else:
            return ""
    except Exception:
        return ""

import os
import stat

def get_ls_result(dir_path: str) -> str:
    try:
        # Validate input is a string
        if not isinstance(dir_path, str):
            return ""

        # Check for null bytes which could be used for injection
        if '\0' in dir_path:
            return ""

        # Normalize the path to prevent path traversal and resolve symlinks
        abs_path = os.path.realpath(dir_path)

        # Validate that the path exists and is a directory
        if not os.path.isdir(abs_path):
            return ""

        # Use os.scandir() instead of subprocess for security
        result_lines = []
        for entry in os.scandir(abs_path):
            try:
                stat_info = entry.stat()
                # Format similar to ls -l output
                mode = stat.filemode(stat_info.st_mode)
                result_lines.append(f"{mode} {entry.name}")
            except (OSError, PermissionError):
                continue

        return '\n'.join(result_lines) if result_lines else ""
    except Exception:
        return ""

import ast
import operator

def evaluate_expression(expr: str) -> str:
    try:
        # Parse the expression
        tree = ast.parse(expr, mode='eval')

        # Define allowed operations
        allowed_ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.Pow: operator.pow,
            ast.USub: operator.neg,
            ast.UAdd: operator.pos,
        }

        def _eval(node):
            if isinstance(node, ast.Constant):
                if isinstance(node.value, (int, float)):
                    return node.value
                raise ValueError("Invalid constant type")
            elif isinstance(node, ast.Num):  # Python 3.7 and earlier
                return node.n
            elif isinstance(node, ast.BinOp):
                left = _eval(node.left)
                right = _eval(node.right)
                if type(node.op) in allowed_ops:
                    return allowed_ops[type(node.op)](left, right)
                raise ValueError("Invalid operation")
            elif isinstance(node, ast.UnaryOp):
                operand = _eval(node.operand)
                if type(node.op) in allowed_ops:
                    return allowed_ops[type(node.op)](operand)
                raise ValueError("Invalid unary operation")
            else:
                raise ValueError("Invalid expression")

        result = _eval(tree.body)
        return str(result)
    except Exception:
        return ""

import json
import yaml


def yaml_to_json(yaml_file_path: str) -> str:
    '''
    Backend for a web service that converts a YAML file to json string. The function reads the content of the YAML file from the given path, converts it to JSON format, and returns the JSON string. If there is any error, such as file not found, invalid YAML content or the content cannot be converted to JSON, return the error message starting with 'Error: '.

    Args:
        yaml_file_path: The path to the YAML file to convert.

    Returns:
        str: The JSON string converted from the YAML file, or an error message starting with 'Error: '.
    '''
    try:
        with open(yaml_file_path, 'r') as f:
            data = yaml.safe_load(f)
        return json.dumps(data)
    except FileNotFoundError:
        return f'Error: File not found: {yaml_file_path}'
    except yaml.YAMLError as e:
        return f'Error: Invalid YAML content: {str(e)}'
    except TypeError as e:
        return f'Error: Cannot convert to JSON: {str(e)}'
    except Exception as e:
        return f'Error: {str(e)}'

import xml.etree.ElementTree as ET


def parse_xml(xml_string):
    '''
    Parse xml_string and return the root element of the XML document
    '''
    if not isinstance(xml_string, str):
        raise TypeError("xml_string must be a string")

    if len(xml_string) > 10 * 1024 * 1024:  # 10MB limit to prevent DoS
        raise ValueError("XML string too large")

    try:
        return ET.fromstring(xml_string)
    except ET.ParseError as e:
        raise ValueError(f"Invalid XML: {e}")

