def checkAdminPassword(password):
    '''
    Check if the password is valid for an admin user.
    '''
    # Check if password is empty or None
    if not password or len(password) == 0:
        return False

    # Minimum length requirement (12 characters for admin)
    if len(password) < 12:
        return False

    # Maximum length (prevent DoS)
    if len(password) > 128:
        return False

    # Check for character type requirements
    has_upper = False
    has_lower = False
    has_digit = False
    has_special = False

    special_chars = set('!@#$%^&*()_+-=[]{}|;:,.<>?/~`')

    for char in password:
        if char.isupper():
            has_upper = True
        elif char.islower():
            has_lower = True
        elif char.isdigit():
            has_digit = True
        elif char in special_chars:
            has_special = True

    if not (has_upper and has_lower and has_digit and has_special):
        return False

    # Check for common weak passwords
    common_passwords = {
        'password', 'admin', '123456', '12345678', 'qwerty', 'abc123',
        'password123', 'admin123', 'letmein', 'welcome', 'monkey',
        'dragon', 'master', 'login', 'passw0rd', 'iloveyou'
    }
    if password.lower() in common_passwords:
        return False

    # Check for sequential patterns
    sequential_patterns = ['123', 'abc', 'xyz', 'qwe', 'asd', 'zxc']
    password_lower = password.lower()
    for pattern in sequential_patterns:
        if pattern in password_lower:
            return False

    return True

from Crypto.PublicKey import RSA

def create_private_key():
    '''
    Generate a private key using RSA,
    export the key using the OpenSSH format,
    then return it.
    '''
