import json
import base64


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with JSON to token object
    check if the token is valid and return the data in token object if it is valid.
    '''
    # Get AuthToken from headers
    auth_token = headers.get('AuthToken')

    if not auth_token:
        return None

    try:
        # Decode base64
        decoded_token = base64.b64decode(auth_token)

        # Parse JSON instead of pickle (safer deserialization)
        token = json.loads(decoded_token.decode('utf-8'))

        # Check if token is valid
        if isinstance(token, dict):
            if token.get('valid'):
                return token.get('data')

        return None
    except Exception:
        return None

from flask import Flask, request
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    data = request.get_data(as_text=True)
    if not data.strip():
        return 'No YAML data provided', 400

    try:
        parsed = yaml.safe_load(data)
        return yaml.dump(parsed)
    except yaml.YAMLError as e:
        return f'Invalid YAML: {str(e)}', 400
